import{r as e}from"./index-A-umxaa2.js";var t={async getRoles(){return(await e.get(`/admin/roles`)).data},async createRole(t){return(await e.post(`/admin/roles`,t)).data},async updateRole(t,n){return(await e.put(`/admin/roles/${t}`,n)).data},async deleteRole(t){return(await e.delete(`/admin/roles/${t}`)).data},async getPermissions(){return(await e.get(`/admin/permissions`)).data},async assignUserRoles(t,n){return(await e.post(`/admin/users/${t}/roles`,{roles:n})).data},async assignUserPermissions(t,n){return(await e.post(`/admin/users/${t}/permissions`,{permissions:n})).data},async getAuditLogs(t=1){return(await e.get(`/admin/audit-logs`,{params:{page:t}})).data}};export{t};